#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
int n,op[N];
double ans,k,c,w,x[N];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>k>>c>>w;
	for(int i=1;i<=n;i++)
	{
		cin>>op[i]>>x[i];
	}
	for(int i=n;i>=1;i--)
	{
		if(op[i]==1) ans=max(ans,x[i]+ans*(1-0.01*k));
		else ans=max(ans,ans*(1+0.01*c)-x[i]);
	}
	cout<<fixed<<setprecision(2)<<ans*w;
	return 0;
}
